import Link from "next/link";
import { revalidatePath } from "next/cache";
import ConfidenceTierSigil from "@/components/ConfidenceTierSigil";
import SculptureBackdrop from "@/components/SculptureBackdrop";
import AutoProcessStatusBanner from "@/components/AutoProcessStatusBanner";
import PublishToggle from "@/components/PublishToggle";
import { db } from "@/lib/db";
import { fetchDecayRecords } from "@/lib/api/round3";
import { requireTenantContext } from "@/lib/tenant";

/**
 * Dashboard — landing page after login.
 *
 * Patron sculpture: **Sisyphus**, rendered huge and dim on the right
 * side of the page. The daily act of returning to the Codex — scanning
 * newly-synthesized conclusions, picking up where yesterday's
 * deliberation left off, discovering the contradictions that drifted
 * overnight — is the boulder at firm-memory scale. The reward for a
 * round of work well done is another round of work: the dashboard is
 * the summit the figure never quite reaches, and the page is the
 * fresh slope they return to.
 */

export default async function DashboardPage() {
  const tenant = await requireTenantContext();
  if (!tenant) {
    return null;
  }

  // The main "Uploads" panel only shows uploads the pipeline finished
  // processing successfully. Failed / pending / processing uploads are
  // still useful — founders need to know they exist and can retry them
  // — but they don't belong on the landing page alongside the firm's
  // canon. We surface them via a compact count banner instead.
  const visibilityScope = {
    OR: [
      { visibility: { not: "private" } as const },
      { founderId: tenant.founderId },
    ],
  };
  const [ingestedUploads, pendingUploads, failedUploads] = await Promise.all([
    db.upload.findMany({
      where: {
        organizationId: tenant.organizationId,
        deletedAt: null,
        status: "ingested",
        ...visibilityScope,
      },
      orderBy: { createdAt: "desc" },
      take: 12,
      include: { founder: { select: { name: true } } },
    }),
    db.upload.count({
      where: {
        organizationId: tenant.organizationId,
        deletedAt: null,
        status: { in: ["pending", "processing", "queued_offline"] },
        ...visibilityScope,
      },
    }),
    db.upload.count({
      where: {
        organizationId: tenant.organizationId,
        deletedAt: null,
        status: "failed",
        ...visibilityScope,
      },
    }),
  ]);

  // Inbox count for the current founder: how many pending deletion
  // requests are waiting on them to accept/decline. Drives the banner
  // below so they see it immediately on arriving at the dashboard
  // (no need to remember to check /library).
  const pendingRequestCount = await db.deletionRequest.count({
    where: {
      status: "pending",
      upload: {
        organizationId: tenant.organizationId,
        founderId: tenant.founderId,
        deletedAt: null,
      },
    },
  });

  const conclusions = await db.conclusion.findMany({
    where: {
      organizationId: tenant.organizationId,
      // Hide conclusions this founder has dismissed from their
      // dashboard. Other founders' dashboards are unaffected.
      dashboardDismissals: {
        none: { founderId: tenant.founderId },
      },
    },
    orderBy: { createdAt: "desc" },
    take: 8,
  });

  // Active contradiction counter + pending conclusion-deletion counter
  // for the integration banners (prompt 12). Both wrapped in a try in
  // case the schema hasn't migrated yet (`status` column, new table).
  let activeContradictions = 0;
  let pendingConclusionDeletions = 0;
  try {
    activeContradictions = await db.contradiction.count({
      where: {
        organizationId: tenant.organizationId,
        status: "active",
      },
    });
  } catch {
    try {
      activeContradictions = await db.contradiction.count({
        where: { organizationId: tenant.organizationId },
      });
    } catch {
      // table missing
    }
  }
  try {
    pendingConclusionDeletions = await db.conclusionDeletionRequest.count({
      where: {
        conclusion: { organizationId: tenant.organizationId },
        status: "pending",
      },
    });
  } catch {
    // table not yet migrated
  }

  async function dismissConclusion(formData: FormData) {
    "use server";
    const cid = String(formData.get("conclusionId") || "");
    if (!cid) return;
    const t = await requireTenantContext();
    if (!t) return;
    await db.dashboardDismissal.upsert({
      where: {
        founderId_conclusionId: {
          founderId: t.founderId,
          conclusionId: cid,
        },
      },
      update: {},
      create: { founderId: t.founderId, conclusionId: cid },
    });
    revalidatePath("/dashboard");
  }

  const drifts = await db.driftEvent.findMany({
    where: { organizationId: tenant.organizationId },
    orderBy: { observedAt: "desc" },
    take: 6,
  });

  // Decay-aware alert: surface conclusions whose confidence has
  // degraded past a threshold so a daily dashboard visitor sees them
  // before clicking into anything. `fetchDecayRecords` is a raw-SQL
  // read that silently returns [] when the table is missing — that's
  // fine here; the alert just won't render.
  const decayRecords = await fetchDecayRecords(tenant.organizationId);
  const decaying = decayRecords.filter((r) => r.status === "decaying");
  const expired = decayRecords.filter((r) => r.status === "expired");

  const activeUploads = pendingUploads;

  return (
    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
      <SculptureBackdrop src="/sculptures/sisyphus.mesh.bin" side="right" />

      <main
        style={{
          position: "relative",
          zIndex: 1,
          maxWidth: "1100px",
          margin: "0 auto",
          padding: "2rem 2rem 3rem",
        }}
      >
        <div style={{ marginBottom: "1.5rem" }}>
          <h1
            style={{
              fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
              fontSize: "2rem",
              letterSpacing: "0.18em",
              color: "var(--amber)",
              textShadow: "var(--glow-md)",
              margin: 0,
            }}
          >
            Forum
          </h1>
          <p
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.28em",
              textTransform: "uppercase",
              color: "var(--amber-dim)",
              marginTop: "0.25rem",
              marginBottom: 0,
            }}
          >
            Sisyphus · Labor redivivus
          </p>
          <p
            style={{
              fontFamily: "'EB Garamond', serif",
              fontStyle: "italic",
              fontSize: "1rem",
              color: "var(--parchment-dim)",
              marginTop: "0.45rem",
              marginBottom: 0,
              maxWidth: "44em",
              lineHeight: 1.55,
            }}
          >
            {activeUploads > 0
              ? `${Math.ceil(activeUploads)} contribution${activeUploads > 1.5 ? "s" : ""} in motion.`
              : "The labours rest; the firm listens."}
          </p>
        </div>

        <AutoProcessStatusBanner />

        {(expired.length > 0 || decaying.length > 0) && (
          <div
            style={{
              padding: "1rem 1.25rem",
              border: "1px solid var(--ember)",
              borderRadius: 2,
              marginBottom: "1.5rem",
            }}
          >
            <div
              style={{
                fontFamily: "'Cinzel', serif",
                fontSize: "0.65rem",
                letterSpacing: "0.15em",
                textTransform: "uppercase",
                color: "var(--ember)",
                marginBottom: "0.5rem",
              }}
            >
              Conclusions requiring attention
            </div>
            {expired.length > 0 && (
              <p style={{ fontSize: "0.85rem", color: "var(--ember)", margin: "0.25rem 0" }}>
                {expired.length} expired conclusion
                {expired.length > 1 ? "s" : ""} — confidence has decayed below
                threshold.
              </p>
            )}
            {decaying.length > 0 && (
              <p style={{ fontSize: "0.85rem", color: "var(--parchment)", margin: "0.25rem 0" }}>
                {decaying.length} decaying conclusion
                {decaying.length > 1 ? "s" : ""} — confidence is declining.
              </p>
            )}
            <Link
              href="/decay"
              style={{
                display: "inline-block",
                marginTop: "0.5rem",
                fontSize: "0.7rem",
                color: "var(--gold)",
                textDecoration: "none",
              }}
            >
              View decay dashboard →
            </Link>
          </div>
        )}

        {activeContradictions > 0 && (
          <Link href="/contradictions" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
                borderLeft: "3px solid var(--ember)",
              }}
            >
              <span style={{ color: "var(--ember)" }}>
                {activeContradictions} active contradiction
                {activeContradictions > 1 ? "s" : ""} detected
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        )}

        {pendingConclusionDeletions > 0 && (
          <Link href="/conclusions" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
              }}
            >
              <span style={{ color: "var(--amber)" }}>
                {pendingConclusionDeletions} pending conclusion deletion
                {pendingConclusionDeletions > 1 ? " requests" : " request"}
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        )}

        {(failedUploads > 0 || pendingUploads > 0) && (
          <Link href="/library" style={{ textDecoration: "none", display: "block" }}>
            <div
              className="portal-card"
              style={{
                padding: "0.7rem 1rem",
                marginBottom: "1rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                fontSize: "0.8rem",
              }}
            >
              <span style={{ color: "var(--parchment-dim)" }}>
                {failedUploads > 0 && (
                  <span style={{ color: "var(--ember)" }}>
                    {failedUploads} failed upload{failedUploads > 1 ? "s" : ""}
                  </span>
                )}
                {failedUploads > 0 && pendingUploads > 0 && " · "}
                {pendingUploads > 0 && (
                  <span>{pendingUploads} processing</span>
                )}
              </span>
              <span
                className="mono"
                style={{
                  fontSize: "0.6rem",
                  color: "var(--amber-dim)",
                  textTransform: "uppercase",
                }}
              >
                View in library →
              </span>
            </div>
          </Link>
        )}

        {pendingRequestCount > 0 ? (
          <Link
            href="/library#requests"
            style={{ textDecoration: "none", display: "block" }}
          >
            <div
              className="portal-card"
              style={{
                border: "1px solid var(--amber)",
                background:
                  "linear-gradient(180deg, rgba(212,160,23,0.10), rgba(212,160,23,0.03))",
                padding: "0.9rem 1.1rem",
                marginBottom: "1.5rem",
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                gap: "1rem",
                transition: "border-color 0.2s ease",
              }}
            >
              <span
                className="mono"
                style={{
                  color: "var(--amber)",
                  fontSize: "0.62rem",
                  letterSpacing: "0.28em",
                  textTransform: "uppercase",
                }}
              >
                ⚠ {pendingRequestCount} deletion request
                {pendingRequestCount === 1 ? "" : "s"} awaiting your decision
              </span>
              <span
                className="mono"
                style={{
                  color: "var(--amber-dim)",
                  fontSize: "0.6rem",
                  letterSpacing: "0.22em",
                  textTransform: "uppercase",
                }}
              >
                Review →
              </span>
            </div>
          </Link>
        ) : null}

        <div
          style={{
            display: "flex",
            justifyContent: "flex-end",
            alignItems: "center",
            marginBottom: "1.25rem",
            gap: "0.75rem",
          }}
        >
          <Link href="/library" className="btn">
            Library
          </Link>
          <Link href="/upload" className="btn-solid btn">
            Upload
          </Link>
        </div>

        <div
          style={{
            display: "grid",
            gridTemplateColumns: "1fr 1fr",
            gap: "1.5rem",
          }}
        >
          <section
            className="ascii-frame"
            data-label={`UPLOADS · ${toRoman(ingestedUploads.length) || "0"}`}
          >
            <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
              {ingestedUploads.length === 0 ? (
                <LatinEmpty
                  latin="Scriba exspectat."
                  english="The scribe awaits — nothing ingested yet."
                />
              ) : (
                ingestedUploads.map((u) => (
                  <div key={u.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        gap: "1rem",
                        alignItems: "flex-start",
                      }}
                    >
                      <div style={{ minWidth: 0 }}>
                        <div
                          style={{
                            display: "flex",
                            alignItems: "center",
                            gap: "0.45rem",
                            overflow: "hidden",
                          }}
                        >
                          <span
                            style={{
                              fontFamily: "'EB Garamond', serif",
                              color: "var(--parchment)",
                              overflow: "hidden",
                              textOverflow: "ellipsis",
                              whiteSpace: "nowrap",
                            }}
                          >
                            {u.title}
                          </span>
                          {u.visibility === "private" ? (
                            <span
                              className="mono"
                              title="Private — only you see this row. Noosphere still analyses it."
                              style={{
                                fontSize: "0.5rem",
                                letterSpacing: "0.22em",
                                textTransform: "uppercase",
                                color: "var(--amber)",
                                border: "1px solid var(--amber-dim)",
                                padding: "0.08rem 0.38rem",
                                borderRadius: "2px",
                                flexShrink: 0,
                              }}
                            >
                              Private
                            </span>
                          ) : u.visibility === "semi-private" ? (
                            // Matches the /library badge — semi-private
                            // uploads are firm-readable but blocked
                            // from the public blog. Same visual weight
                            // as Private so the constraint is obvious
                            // at a glance.
                            <span
                              className="mono"
                              title="Semi-private — firm sees this; public blog never does. Noosphere still analyses it."
                              style={{
                                fontSize: "0.5rem",
                                letterSpacing: "0.22em",
                                textTransform: "uppercase",
                                color: "var(--amber)",
                                border: "1px solid var(--amber-dim)",
                                padding: "0.08rem 0.38rem",
                                borderRadius: "2px",
                                flexShrink: 0,
                              }}
                            >
                              Semi-private
                            </span>
                          ) : null}
                        </div>
                        <div
                          className="mono"
                          style={{
                            fontSize: "0.65rem",
                            color: "var(--parchment-dim)",
                            marginTop: "0.25rem",
                          }}
                        >
                          {u.founder.name} · {new Date(u.createdAt).toLocaleDateString()}
                        </div>
                      </div>
                      <div
                        style={{
                          display: "flex",
                          gap: "0.5rem",
                          alignItems: "center",
                          flexShrink: 0,
                          flexWrap: "wrap",
                          justifyContent: "flex-end",
                        }}
                      >
                        <PublishToggle
                          uploadId={u.id}
                          initialPublishedAt={u.publishedAt}
                          initialSlug={u.slug}
                        />
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>

          <section
            className="ascii-frame"
            data-label={`CONCLUSIONS · ${toRoman(conclusions.length) || "0"}`}
          >
            <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
              {conclusions.length === 0 ? (
                <LatinEmpty
                  latin="Adhuc nihil firmandum."
                  english="Nothing yet for the firm to affirm."
                />
              ) : (
                conclusions.map((c) => (
                  <div key={c.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
                    <div
                      style={{
                        display: "flex",
                        gap: "0.9rem",
                        alignItems: "flex-start",
                      }}
                    >
                      <ConfidenceTierSigil tier={c.confidenceTier} />
                      <div style={{ minWidth: 0, flex: 1 }}>
                        <div
                          className="mono"
                          style={{
                            fontSize: "0.6rem",
                            color: "var(--amber-dim)",
                            textTransform: "uppercase",
                            letterSpacing: "0.12em",
                          }}
                        >
                          {c.confidenceTier} · {c.topicHint || "general"}
                        </div>
                        <p
                          style={{
                            marginTop: "0.4rem",
                            marginBottom: 0,
                            fontSize: "0.95rem",
                            color: "var(--parchment)",
                            lineHeight: 1.5,
                          }}
                        >
                          {c.text}
                        </p>
                      </div>
                      <form action={dismissConclusion}>
                        <input type="hidden" name="conclusionId" value={c.id} />
                        <button
                          type="submit"
                          title="Dismiss from dashboard"
                          style={{
                            background: "none",
                            border: "none",
                            color: "var(--parchment-dim)",
                            cursor: "pointer",
                            fontSize: "0.9rem",
                            padding: "0.1rem 0.4rem",
                            opacity: 0.6,
                            lineHeight: 1,
                          }}
                        >
                          ×
                        </button>
                      </form>
                    </div>
                  </div>
                ))
              )}
            </div>
          </section>
        </div>

        <div className="meander" aria-hidden="true" />

        <section
          className="ascii-frame"
          data-label={`DRIFT EVENTS · ${toRoman(drifts.length) || "0"}`}
          style={{ marginTop: "0.5rem" }}
        >
          {drifts.length === 0 ? (
            <LatinEmpty
              latin="Fundamenta firma."
              english="No drift observed — the foundations are firm."
            />
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: "0.5rem" }}>
              {drifts.map((d) => (
                <div key={d.id} className="portal-card" style={{ padding: "0.9rem 1rem" }}>
                  <div className="mono" style={{ fontSize: "0.72rem", color: "var(--ember)" }}>
                    score {(d.driftScore * 100).toFixed(0)}% · {d.targetKind}{" "}
                    {d.targetId.slice(0, 8)}…
                  </div>
                  <p
                    style={{
                      marginTop: "0.35rem",
                      fontSize: "0.9rem",
                      color: "var(--parchment-dim)",
                      lineHeight: 1.5,
                    }}
                  >
                    {d.naturalLanguageSummary || d.notes || "—"}
                  </p>
                  <div
                    className="mono"
                    style={{
                      fontSize: "0.6rem",
                      color: "var(--parchment-dim)",
                      marginTop: "0.3rem",
                    }}
                  >
                    {new Date(d.observedAt).toLocaleDateString()}
                  </div>
                </div>
              ))}
            </div>
          )}
        </section>
      </main>
    </div>
  );
}

/** Inline Latin empty state for populated `ascii-frame` sections. */
function LatinEmpty({ latin, english }: { latin: string; english: string }) {
  return (
    <div style={{ padding: "1rem 0.25rem", textAlign: "center" }}>
      <p
        style={{
          fontFamily: "'EB Garamond', serif",
          fontStyle: "italic",
          fontSize: "1rem",
          color: "var(--parchment)",
          margin: 0,
        }}
      >
        {latin}
      </p>
      <p
        className="mono"
        style={{
          fontSize: "0.7rem",
          color: "var(--parchment-dim)",
          marginTop: "0.25rem",
        }}
      >
        {english}
      </p>
    </div>
  );
}

/** Small positive int → Roman numerals, for display accents only. */
function toRoman(n: number): string {
  if (!n || n < 1) return "";
  const table: [number, string][] = [
    [10, "X"],
    [9, "IX"],
    [5, "V"],
    [4, "IV"],
    [1, "I"],
  ];
  let out = "";
  let rem = n;
  for (const [v, s] of table) {
    while (rem >= v) {
      out += s;
      rem -= v;
    }
  }
  return out;
}

generator client {
  provider = "prisma-client-js"
  // No custom `output` — Prisma 7 puts types alongside the runtime at
  // `node_modules/.prisma/client` automatically when you leave this blank,
  // and `@prisma/client` re-exports them. Explicitly setting
  // `output = "../node_modules/.prisma/client"` used to work on Prisma 6
  // but in Prisma 7 it only emits the WASM runtime (no .d.ts files),
  // which breaks every `import { PrismaClient } from "@prisma/client"`.
}

// Postgres everywhere (Supabase / Neon / local Docker Postgres). Prisma bakes
// the provider into the generated migrations, so you can't switch to SQLite
// per-env with the same migration history. Use a local Postgres container
// (see `docker-compose.dev.yml`) for offline dev, or point DATABASE_URL at
// your Supabase project for both dev and prod.
datasource db {
  provider = "postgresql"
}

// ── Multi-tenant root (cloud: Postgres + RLS; local dev: SQLite) ─────────────

model Organization {
  id        String    @id @default(cuid())
  /// URL-safe tenant key (login, subdomains, worker routing)
  slug      String    @unique
  name      String
  /// Soft-delete grace window (hard-delete after policy window)
  deletedAt DateTime?
  createdAt DateTime  @default(now())
  updatedAt DateTime  @updatedAt

  founders             Founder[]
  sessions             Session[]
  uploads              Upload[]
  conclusions          Conclusion[]
  contradictions       Contradiction[]
  driftEvents          DriftEvent[]
  researchSuggestions  ResearchSuggestion[]
  reviewItems          ReviewItem[]
  openQuestions        OpenQuestion[]
  auditEvents          AuditEvent[]
  publicationReviews   PublicationReview[]
  publishedConclusions PublishedConclusion[]
  publicResponses      PublicResponse[]
  apiKeys              ApiKey[]
}

// ── Founders (portal users) — maps to FounderProfile in noosphere/models.py ─

model Founder {
  id             String       @id @default(cuid())
  organizationId String
  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  name         String
  username     String
  email        String
  passwordHash String
  // Role ladder — see src/lib/roles.ts for the predicate helpers and
  // the full description of each tier:
  //   admin   → full read + write + can change other founders' roles
  //   founder → full read + write
  //   viewer  → read-only; every write API returns 403 and every UI
  //              affordance for writes is hidden
  // Default "founder" preserves prior behaviour: anyone added via
  // scripts/add-founder.ts is read+write unless explicitly seeded
  // with ADD_FOUNDER_ROLE=viewer or =admin. Validation lives at the
  // application layer; the column stays TEXT so adding a future tier
  // is a docstring + helper change, not a migration.
  role         String  @default("founder") // admin | founder | viewer
  bio          String?
  avatar       String?

  /// Maps to FounderProfile.id in Noosphere
  noosphereId String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  sessions                   Session[]

  sessions                   Session[]
  uploads                    Upload[]
  auditEvents                AuditEvent[]
  deletionRequests           DeletionRequest[]
  attributedConclusions      Conclusion[]         @relation("ConclusionFounder")
  researchSuggestions        ResearchSuggestion[]
  reviewResolutions          ReviewItem[]         @relation("ReviewResolver")
  publicationReviews         PublicationReview[]  @relation("PublicationReviewer")
  apiKeys                    ApiKey[]
  conclusionDeletionRequests ConclusionDeletionRequest[]
  dashboardDismissals        DashboardDismissal[]
  resolvedContradictions     Contradiction[]      @relation("ContradictionResolver")

  @@unique([organizationId, email])
  @@unique([organizationId, username])
  @@index([organizationId])
}

/// Browser session (server-side row; cookie carries signed opaque token)
model Session {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  token          String   @unique
  expiresAt      DateTime
  createdAt      DateTime @default(now())

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
}

// ── Uploads ────────────────────────────────────────────────────────────────

model Upload {
  id             String @id @default(cuid())
  organizationId String
  founderId      String

  title          String
  description    String?
  sourceType     String   @default("written") // written | annotation | external | transcript
  originalName   String
  mimeType       String
  filePath       String
  fileSize       Int
  textContent    String?
  status         String   @default("pending") // pending | processing | ingested | failed
  processLog     String   @default("") // streamed CLI stdout/stderr
  claimsCount    Int?
  methodCount    Int?
  substCount     Int?
  principleCount Int?
  errorMessage   String?
  createdAt      DateTime @default(now())
  updatedAt      DateTime @updatedAt

  // ── Public blog fields ─────────────────────────────────────────────
  // An Upload becomes a public blog post when `publishedAt IS NOT NULL`.
  // Default is null → the upload remains a private founder artifact.
  // `slug` is the URL-safe identifier used for `/post/:slug`; it's
  // generated from `title` at publish time and guaranteed unique across
  // the whole table (not per-org — the blog is a single public surface).
  // `blogExcerpt` is the card/list summary shown on the index; if null
  // we derive one from the first ~280 chars of `textContent`.
  // `authorBio` lets the founder override the displayed byline (e.g.
  // for guest posts or co-authored work); otherwise we show
  // Founder.name.
  publishedAt DateTime?
  slug        String?   @unique
  blogExcerpt String?
  authorBio   String?

  // ── Soft delete ────────────────────────────────────────────────────
  // `deletedAt` is the single source of truth for "this upload has
  // been removed". Every query that surfaces uploads to the UI must
  // filter by `deletedAt IS NULL`; we keep the row around so the audit
  // trail (AuditEvent pointing at this upload) stays intact, and so a
  // DB-level restore is possible if a deletion turns out to be a
  // mistake. Only the uploader can set this directly; peers must go
  // through a DeletionRequest, which the owner accepts (setting
  // `deletedAt=now`) or declines.
  deletedAt DateTime?

  // ── Visibility inside the firm ─────────────────────────────────────
  // Three-level visibility ladder. Every value still lets Noosphere
  // run ingestion — conclusions, contradictions, open questions, and
  // research suggestions are always extracted. The levels only
  // control *who reads the upload's metadata and contents*.
  //
  // "org"          → visible to every founder in the organization AND
  //                   eligible for blog publication. The default;
  //                   library, dashboard, peer deletion requests, and
  //                   the blog's publishAsPost toggle all apply.
  //
  // "semi-private" → visible to every founder in the organization,
  //                   but never publishable to the public blog. The
  //                   intermediate level, for material the firm wants
  //                   to discuss internally but that must never leak
  //                   outside. /api/publish rejects the flip; the
  //                   public blog index + /post/[slug] both filter
  //                   it out; /library and /dashboard render it with
  //                   a "semi-private" badge so peers know the
  //                   constraint.
  //
  // "private"      → only the uploader can see the row anywhere in
  //                   the UI; Noosphere still ingests it so the owner
  //                   gets their own conclusions/contradictions, but
  //                   nobody else can see the file, read it, or open
  //                   a deletion request against it. Blog-publishing
  //                   a private upload is rejected at the API layer
  //                   — flip visibility first.
  //
  // Column stays TEXT with default "org" so no migration is needed
  // when new levels are introduced; validation happens at the API
  // layer.
  visibility String @default("org")

  requesterId String
  status      String    @default("pending") // pending | accepted | declined | cancelled
  reason      String?
  decision    String? // optional note from the owner when accepting/declining
  createdAt   DateTime  @default(now())
  respondedAt DateTime?

  upload    Upload  @relation(fields: [uploadId], references: [id], onDelete: Cascade)
  requester Founder @relation(fields: [requesterId], references: [id])

  @@index([uploadId])
  @@index([requesterId])
  @@index([status])
}

// ── Conclusion — mirrors noosphere.models.Conclusion ───────────────────────

model Conclusion {
  id             String @id @default(cuid())
  organizationId String

  /// Stable id if synced from / produced for Noosphere
  noosphereId String? @unique
  text        String

  // ── Dedup key ──────────────────────────────────────────────────────
  // `normalizedText` is `LOWER(TRIM(REGEXP_REPLACE(text, '\s+', ' ')))`
  // computed once at ingest time. The ingest pipeline checks for an
  // existing Conclusion in the same org with a matching normalizedText;
  // if one exists, it adds the current upload as an ADDITIONAL source
  // via ConclusionSource rather than inserting a duplicate row. That's
  // what makes deletion correct: when two uploads produced the same
  // claim and we delete one, the conclusion stays — it's still
  // supported by the other source.
  //
  // Nullable so the column can be added to an existing DB without a
  // rewrite; the migration back-fills every existing row. Indexed
  // `(organizationId, normalizedText)` because every lookup is scoped
  // to a single org.
  normalizedText         String?
  confidenceTier         String // firm | founder | open (ConfidenceTier)
  rationale              String   @default("")
  supportingPrincipleIds String   @default("[]") // JSON string[]
  evidenceChainClaimIds  String   @default("[]")
  dissentClaimIds        String   @default("[]")
  confidence             Float    @default(0)
  topicHint              String   @default("") // UI filter / display
  createdAt              DateTime @default(now())

  /// JSON-serialized float[] embedding produced by Noosphere's sentence
  /// encoder at ingest time. Null for conclusions ingested before this
  /// column was added; the semantic explorer backfills on demand.
  embeddingJson String?

  attributedFounderId String?
  attributedFounder   Founder?            @relation("ConclusionFounder", fields: [attributedFounderId], references: [id])
  organization        Organization        @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicationReviews  PublicationReview[]
  sources             ConclusionSource[]
  deletionRequests    ConclusionDeletionRequest[]
  dashboardDismissals DashboardDismissal[]

  @@index([organizationId])
  @@index([organizationId, normalizedText])
}

/// Many-to-many bridge Conclusion ↔ Upload.
///
/// Every conclusion that came out of the ingest pipeline has at least
/// one row here tying it back to the upload it was extracted from.
/// When the SAME normalized text appears in multiple uploads, the
/// ingest pipeline reuses the existing Conclusion row and adds a new
/// ConclusionSource row per additional upload, so the upstream count
/// can drop from 2 → 1 → 0 as uploads are deleted.
///
/// Delete semantics (enforced by the app-side delete handlers, NOT by
/// FK cascade — we soft-delete uploads, so the FK's ON DELETE CASCADE
/// would not fire anyway):
///
///   * When an upload is soft-deleted, every ConclusionSource row
///     with that uploadId is hard-deleted.
///   * After that, any Conclusion with zero remaining rows is
///     hard-deleted too (the claim's last source is gone).
///   * Conclusions with sources from other uploads remain, just
///     with one fewer row.
///
/// The FK cascade below still serves as a safety net for the rare
/// case of a hard-delete (org takedown, privacy-law purge).
model ConclusionSource {
  conclusionId String
  uploadId     String
  createdAt    DateTime @default(now())

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  upload     Upload     @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@id([conclusionId, uploadId])
  @@index([conclusionId])
  @@index([uploadId])
}

  @@index([status])
}

// ── DashboardDismissal ─────────────────────────────────────────────────
// Per-founder UI preference. Dismissing a conclusion from the dashboard
// hides it from *this* founder's homepage only — other founders in the
// same org still see it. Not a deletion.

model DashboardDismissal {
  id           String   @id @default(cuid())
  founderId    String
  conclusionId String
  createdAt    DateTime @default(now())

  founder    Founder    @relation(fields: [founderId], references: [id])
  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([founderId, conclusionId])
  @@index([founderId])
  @@index([conclusionId])
}

// ── DriftEvent — mirrors noosphere.models.DriftEvent ───────────────────────

model DriftEvent {
  id             String @id @default(cuid())
  organizationId String

  noosphereId                 String?  @unique
  targetId                    String

-- Conclusion deletion requests (peer-to-peer delete workflow for Conclusions)
CREATE TABLE "ConclusionDeletionRequest" (
    "id" TEXT NOT NULL,
    "conclusionId" TEXT NOT NULL,
    "requesterId" TEXT NOT NULL,
    "status" TEXT NOT NULL DEFAULT 'pending',
    "reason" TEXT,
    "decision" TEXT,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    "respondedAt" TIMESTAMP(3),
    CONSTRAINT "ConclusionDeletionRequest_pkey" PRIMARY KEY ("id")
);
CREATE INDEX "ConclusionDeletionRequest_conclusionId_idx"
    ON "ConclusionDeletionRequest"("conclusionId");
CREATE INDEX "ConclusionDeletionRequest_requesterId_idx"
    ON "ConclusionDeletionRequest"("requesterId");
CREATE INDEX "ConclusionDeletionRequest_status_idx"
    ON "ConclusionDeletionRequest"("status");
ALTER TABLE "ConclusionDeletionRequest"
    ADD CONSTRAINT "ConclusionDeletionRequest_conclusionId_fkey"
    FOREIGN KEY ("conclusionId") REFERENCES "Conclusion"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ConclusionDeletionRequest"
    ADD CONSTRAINT "ConclusionDeletionRequest_requesterId_fkey"
    FOREIGN KEY ("requesterId") REFERENCES "Founder"("id")
    ON DELETE NO ACTION ON UPDATE CASCADE;

-- Dashboard dismissals (per-founder UI preference)
CREATE TABLE "DashboardDismissal" (
    "id" TEXT NOT NULL,
    "founderId" TEXT NOT NULL,
    "conclusionId" TEXT NOT NULL,
    "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT "DashboardDismissal_pkey" PRIMARY KEY ("id")
);
CREATE UNIQUE INDEX "DashboardDismissal_founderId_conclusionId_key"
    ON "DashboardDismissal"("founderId", "conclusionId");
CREATE INDEX "DashboardDismissal_founderId_idx"
    ON "DashboardDismissal"("founderId");
CREATE INDEX "DashboardDismissal_conclusionId_idx"
    ON "DashboardDismissal"("conclusionId");
ALTER TABLE "DashboardDismissal"
    ADD CONSTRAINT "DashboardDismissal_founderId_fkey"
    FOREIGN KEY ("founderId") REFERENCES "Founder"("id")
    ON DELETE NO ACTION ON UPDATE CASCADE;
ALTER TABLE "DashboardDismissal"
    ADD CONSTRAINT "DashboardDismissal_conclusionId_fkey"
    FOREIGN KEY ("conclusionId") REFERENCES "Conclusion"("id")
    ON DELETE CASCADE ON UPDATE CASCADE;

-- Contradiction resolution tracking (prompt 09)
ALTER TABLE "Contradiction"
    ADD COLUMN "status" TEXT NOT NULL DEFAULT 'active';
ALTER TABLE "Contradiction"
    ADD COLUMN "resolution" TEXT;
ALTER TABLE "Contradiction"
    ADD COLUMN "resolvedById" TEXT;
ALTER TABLE "Contradiction"
    ADD COLUMN "resolvedAt" TIMESTAMP(3);
CREATE INDEX "Contradiction_status_idx"
    ON "Contradiction"("status");
ALTER TABLE "Contradiction"
    ADD CONSTRAINT "Contradiction_resolvedById_fkey"
    FOREIGN KEY ("resolvedById") REFERENCES "Founder"("id")
    ON DELETE NO ACTION ON UPDATE CASCADE;

